2	import { describe, it, expect } from "vitest";
3	import { runScenario } from "./claim-office.js";
4	
5	describe("MHPCO Claim Office", () => {
6	  // === Quote: empty and basic single items ===
7	  it("should return premium of 5 G (processing fee only) for an empty item list", () => {
8	    const result = runScenario({
9	      command: "quote",
10	      customer: { yearsInsured: 0, contractNumber: 1 },
11	      items: [],
12	    });
13	    expect(result).toEqual({ premium: 5 });
14	  });
15	  it("should quote a single sword at 110 G (100 base + 10 first-insurance + 5 fee)", () => {
16	    const result = runScenario({
17	      command: "quote",
18	      customer: { yearsInsured: 0, contractNumber: 1 },
19	      items: [{ type: "sword", material: "steel", enchantment: 0, cursed: false }],
20	    });
21	    expect(result).toEqual({ premium: 115 });
22	  });
23	  it("should quote a single amulet at 71 G (60 base + 6 first-insurance + 5 fee)", () => {
24	    const result = runScenario({
25	      command: "quote",
26	      customer: { yearsInsured: 0, contractNumber: 1 },
27	      items: [{ type: "amulet", material: "silver", enchantment: 0, cursed: false }],
28	    });
29	    expect(result).toEqual({ premium: 71 });
30	  });
31	  it("should quote a single staff at 93 G (80 base + 8 first-insurance + 5 fee)", () => {
32	    const result = runScenario({
33	      command: "quote",
34	      customer: { yearsInsured: 0, contractNumber: 1 },
35	      items: [{ type: "staff", material: "wood", enchantment: 0, cursed: false }],
36	    });
37	    expect(result).toEqual({ premium: 93 });
38	  });
39	  it.todo("should quote a single potion at 49 G (40 base + 4 first-insurance + 5 fee)");
40	  it.todo("should quote a single rune at 33 G (25 base + 2.5 first-insurance + 5 fee, rounded up)");
41	  it.todo("should quote a single moonstone at 33 G (25 base + 2.5 first-insurance + 5 fee, rounded up)");
42	
43	  // === Quote: multiple distinct items ===
44	  it.todo("should quote multiple distinct items by summing their item premiums plus the 5 G fee");
45	
46	  // === Quote: components and blocks of 3 alike ===
47	  it.todo("should quote exactly 3 alike runes as a block with 60 G base premium (plus first-insurance and fee)");
48	  it.todo("should quote exactly 3 alike moonstones as a block with 60 G base premium (plus first-insurance and fee)");
49	  it.todo("should NOT treat 4 alike runes as a block (charge each rune individually)");
50	  it.todo("should NOT treat 2 alike runes as a block (charge each rune individually)");
51	
52	  // === Quote: item-specific modifiers ===
53	  it.todo("should add 50% cursed surcharge on a cursed item's base premium");
54	  it.todo("should add 30% high-enchantment surcharge for an item with enchantment >= 5");
55	  it.todo("should NOT add high-enchantment surcharge for enchantment level < 5");
56	  it.todo("should stack cursed and high-enchantment surcharges additively on the item's base premium");
57	
58	  // === Quote: policy-wide modifiers ===
59	  it.todo("should apply -20% loyalty discount when customer has been insured for >= 2 years");
60	  it.todo("should NOT apply loyalty discount when customer has been insured < 2 years");
61	  it.todo("should apply -15% follow-up discount for the customer's second contract");
62	  it.todo("should NOT apply follow-up discount for the customer's first contract");
63	
64	  // === Quote: multiple items of same type (separate insurance) ===
65	  it.todo("should treat two swords as separate insurance entries (each charged individually)");
66	
67	  // === Quote: rounding ===
68	  it.todo("should round the final premium UP to whole G in MHPCO's favor");
69	
70	  // === Quote: integration examples from spec ===
71	  it.todo("should quote newcomer's cursed sword (steel, enchantment 3) at 165 G");
72	  it.todo("should quote 3-year customer's 2nd contract cursed sword (steel, enchantment 7) at 160 G");
73	
74	  // === Claim: basic single damage ===
75	  it.todo("should pay out damage minus 100 G deductible for a single damaged item");
76	  it.todo("should report remainingCap as 2x unmodified insurance sum minus payout after a claim");
77	
78	  // === Claim: enchantment and material clauses ===
79	  it.todo("should pay only 50% reimbursement when damaged item has enchantment >= 8");
80	  it.todo("should pay full reimbursement when damaged item is made of dragon material (overrides 50% clause)");
81	  it.todo("should NOT apply enchantment/material clauses to runes or moonstones");
82	
83	  // === Claim: cap enforcement ===
84	  it.todo("should cap total payout at 2x unmodified insurance sum across multiple claim events");
85	  it.todo("should round payout DOWN to whole G in MHPCO's favor");
86	
87	  // === CLI integration / error cases ===
88	  it.todo("should exit non-zero and write to stderr when quote contains an unknown item type");
89	  it.todo("should exit non-zero when a claim references an item not in the policy");
90	  it.todo("should exit non-zero when a claim has more damage entries of a type than the policy covers");
91	  it.todo("should exit non-zero when a claim contains a negative damage amount");
