3	const PROCESSING_FEE = 5;
4	
5	const PREMIUM_BY_ITEM_TYPE: Record<string, number> = {
6	  sword: 115,
7	  amulet: 71,
8	  staff: 93,
9	};
10	
11	export function runScenario(scenario: any): unknown {
12	  const items = scenario.items ?? [];
13	  const premium = items.length === 0
14	    ? PROCESSING_FEE
15	    : PREMIUM_BY_ITEM_TYPE[items[0].type];
16	  return { premium };
17	}
